mapper.select:
SELECT sku.id AS sku_id, sku.sale_price, ( SELECT MIN(inner_sku.sale_price) FROM product_sku inner_sku WHERE inner_sku.spu_id = p.id AND inner_sku.status = 'on_sale' ) AS min_price, ( SELECT MAX(inner_sku.sale_price) FROM product_sku inner_sku WHERE inner_sku.spu_id = p.id AND inner_sku.status = 'on_sale' ) AS max_price, ( SELECT COALESCE(SUM(inner_inv.available_stock), 0) FROM product_sku inner_sku LEFT JOIN inventory inner_inv ON inner_inv.sku_id = inner_sku.id WHERE inner_sku.spu_id = p.id AND inner_sku.status = 'on_sale' ) AS total_available_stock, COALESCE(inv.available_stock, 0) AS available_stock FROM product_sku sku JOIN product_spu p ON p.id = sku.spu_id LEFT JOIN inventory inv ON inv.sku_id = sku.id WHERE p.status = 'on_sale' AND sku.status = 'on_sale' AND sku.id IN
#{skuId}
ORDER BY sku.id ASC
